// Parametri
vec2 c = (uv - 0.5) * 3.0 - vec2(0.7, 0.0);
vec2 z = vec2(0.0);

float iter = 0.0;
float maxIter = 100.0;

// Ciclo principale del Mandelbrot
for(float i = 0.0; i < maxIter; i++) {
    // Formula: Z = Z^2 + C
    float x = (z.x * z.x - z.y * z.y) + c.x;
    float y = (2.0 * z.x * z.y) + c.y;

    // Controllo di fuga (modulo > 2, quindi modulo^2 > 4)
    if((x * x + y * y) > 4.0) break;

    z.x = x;
    z.y = y;
    iter++;
}

// Colorazione
float t = iter / maxIter;

// Smoothing della sfumatura
t = pow(t, 0.5);

// Se il punto è all'interno del set (non è fuggito), colora di nero
if (iter >= maxIter - 0.5) return vec3(0.0);

// Altrimenti interpola tra i due colori definiti nell'interfaccia (u_col2 e u_col1)
return mix(u_col2, u_col1, t);
